import anthropic
from typing import Callable

client = anthropic.Anthropic()

def run_agentic_loop(
    messages: list[dict],
    tools: list[dict],
    tool_handlers: dict[str, Callable],
    system: str,
    model: str = "claude-sonnet-5",
    max_iterations: int = 10,
) -> str:
    for iteration in range(max_iterations):
        response = client.messages.create(
            model=model,
            max_tokens=4096,
            system=system,
            tools=tools,
            messages=messages,
        )

        if response.stop_reason == "end_turn":
            return next(
                (b.text for b in response.content if b.type == "text"),
                "",
            )

        if response.stop_reason == "tool_use":
            messages.append({"role": "assistant", "content": response.content})
            tool_results = []
            for block in response.content:
                if block.type == "tool_use":
                    handler = tool_handlers.get(block.name)
                    if handler is None:
                        result = f"Unknown tool: {block.name}"
                        is_error = True
                    else:
                        try:
                            result = handler(**block.input)
                            is_error = False
                        except Exception as exc:
                            result = f"Tool error: {exc}"
                            is_error = True
                    tool_results.append({
                        "type": "tool_result",
                        "tool_use_id": block.id,
                        "content": str(result),
                        "is_error": is_error,
                    })
            messages.append({"role": "user", "content": tool_results})
            continue

        raise RuntimeError(f"Unexpected stop_reason: {response.stop_reason}")

    raise RuntimeError(f"Loop did not terminate after {max_iterations} iterations")

async def rate_limited_loop(
    messages: list[dict],
    tools: list[dict],
    handlers: dict,
    system: str,
    max_tool_calls_per_turn: int = 20,
) -> str:
    tool_call_count = 0

    for _ in range(30):
        response = await client.messages.create(
            model="claude-sonnet-5",
            max_tokens=4096,
            system=system,
            tools=tools,
            messages=messages,
        )

        if response.stop_reason == "end_turn":
            return next((b.text for b in response.content if b.type == "text"), "")

        new_calls = sum(1 for b in response.content if b.type == "tool_use")
        tool_call_count += new_calls
        messages.append({"role": "assistant", "content": response.content})

        if tool_call_count > max_tool_calls_per_turn:
            last_tool_id = next(
                b.id for b in reversed(response.content) if b.type == "tool_use"
            )
            messages.append({
                "role": "user",
                "content": [{
                    "type": "tool_result",
                    "tool_use_id": last_tool_id,
                    "content": "Tool call limit reached. Summarise findings so far.",
                    "is_error": False,
                }],
            })
            final = await client.messages.create(
                model="claude-haiku-4-5-20251001",
                max_tokens=1024,
                system=system,
                messages=messages,
            )
            return next((b.text for b in final.content if b.type == "text"), "")

        tool_results = []
        for b in [x for x in response.content if x.type == "tool_use"]:
            try:
                result = await handlers[b.name](**b.input)
                is_error = False
            except Exception as exc:
                result = str(exc)
                is_error = True
            tool_results.append({
                "type": "tool_result",
                "tool_use_id": b.id,
                "content": str(result),
                "is_error": is_error,
            })
        messages.append({"role": "user", "content": tool_results})

    return "Loop limit reached"
